// Runtime dispatch: VQMACC tiling vectorizes along N (no VREDSUM),
// VD4DOTS vectorizes along K (needs VREDSUM per output element).
// When N >= 128, VQMACC tiling wins by avoiding O(M*N) VREDSUM overhead.
const long n_threshold = 128;

if (out_tensor_ch >= n_threshold)
{
    // Large N: use VQMACC tiling path (transpose + tiled GEMM)
    uint32_t tiling_size = 256;
    const long align_byte = 64;
    unsigned long addr_in_tmp_buf;
    int8_t *pOut = out_tensor;
    int8_t *src1 = (int8_t *) in_tensor;
    int8_t *src2;
    int32_t *dst_i32;

    if ((stride_x == 1) && (stride_y == 1))
    {
        src2 = (int8_t *)tmp_buf;
    }
    else
    {
        src2 = (int8_t *)tmp_buf + sizeof(*in_tensor) * tiling_size * in_tensor_ch;
        src2 = (int8_t *)nn_align((unsigned long)src2, align_byte);
    }

    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_i32 = (int32_t *)addr_in_tmp_buf;

    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch);

    if ((stride_x == 1) && (stride_y == 1))
    {
        for(int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
        {
            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
                                                          src2,
                                                          dst_i32,
                                                          pOut,
                                                          out_scale,
                                                          out_shift,
                                                          in_tensor_dim_x * in_tensor_dim_y,
                                                          in_tensor_ch,
                                                          out_tensor_ch,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          contri_buf,
                                                          tiling_size);
            src1 += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        }
    }
    else
    {
        for(int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
        {
            int8_t *pBuffer = (int8_t *)tmp_buf;
            int col_counter = 0;
            int16_t i_out_y, i_out_x;

            for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
            {
                for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
                {
                    nn_dup_s8((int8_t *)in_tensor + (i_out_y * stride_y * in_tensor_dim_x + i_out_x * stride_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    pBuffer += in_tensor_ch;
                    col_counter++;

                    if (col_counter == tiling_size)
                    {
                        pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
                                                                      src2,
                                                                      dst_i32,
                                                                      pOut,
                                                                      out_scale,
                                                                      out_shift,
                                                                      col_counter,
                                                                      in_tensor_ch,
                                                                      out_tensor_ch,
                                                                      out_offset,
                                                                      act_min,
                                                                      act_max,
                                                                      contri_buf,
                                                                      tiling_size);
                        col_counter = 0;
                        pBuffer = (int8_t *)tmp_buf;
                    }
                }
            }

            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
                                                          src2,
                                                          dst_i32,
                                                          pOut,
                                                          out_scale,
                                                          out_shift,
                                                          col_counter,
                                                          in_tensor_ch,
                                                          out_tensor_ch,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          contri_buf,
                                                          tiling_size);
            in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        }
    }
}
else
{
    // Small/medium N: use direct VD4DOTS path (no VREDSUM overhead at small N)
    if ((stride_x == 1) && (stride_y == 1))
    {
        const long lhs_rows = in_tensor_dim_x * in_tensor_dim_y * in_tensor_batch;
        const long rhs_rows = out_tensor_ch;
        const long rhs_cols = in_tensor_ch;
        const long lhs_cols_offset = rhs_cols;

        nn_mat_mult_nt_t_s8_v2(in_tensor,
                               ker_weight,
                               bias,
                               out_tensor,
                               out_scale,
                               out_shift,
                               lhs_rows,
                               rhs_rows,
                               rhs_cols,
                               in_offset,
                               out_offset,
                               act_min,
                               act_max,
                               lhs_cols_offset,
                               contri_buf);
    }
    else
    {
        const long lhs_rows = out_tensor_dim_x;
        const long rhs_rows = out_tensor_ch;
        const long rhs_cols = in_tensor_ch;
        const long input_inc = in_tensor_dim_x * stride_y * rhs_cols;
        const long output_inc = out_tensor_dim_x * rhs_rows;
        const long lhs_cols_offset = rhs_cols * stride_x;

        for (long i_batch = 0; i_batch < in_tensor_batch; i_batch++)
        {
            const int8_t *in_tensor2 = in_tensor + (i_batch * in_tensor_dim_y * in_tensor_dim_x * in_tensor_ch);
            for (long i_output_y = 0; i_output_y < out_tensor_dim_y; i_output_y++)
            {
                nn_mat_mult_nt_t_s8_v2(in_tensor2,
                                       ker_weight,
                                       bias,
                                       out_tensor,
                                       out_scale,
                                       out_shift,
                                       lhs_rows,
                                       rhs_rows,
                                       rhs_cols,
                                       in_offset,
                                       out_offset,
                                       act_min,
                                       act_max,
                                       lhs_cols_offset,
                                       contri_buf);
                in_tensor2 += input_inc;
                out_tensor += output_inc;
            }
        }
    }
}

