 38→static inline void vec_mat_mul_rvv_tiling(const MM_TYPE* src1, const MM_TYPE* src2, MM_TYPE* dst, uint32_t row, uint32_t col, uint32_t col2, uint32_t tiling_size)
 39→{
 40→    //4*4 by 4*vl
 41→    int row_4 = row >> 2;
 42→    int max_row = row_4 << 2;
 43→
 44→    const MM_TYPE* A = src1;
 45→    const MM_TYPE* B = src2;
 46→    const MM_TYPE* C = dst;
 47→    int r, k, kk, cc, vl;
 48→    int kk_tiling_size, cc_tiling_size, max_kk_tiling_size;
 49→    const MM_TYPE* A11, * B11, \
 50→                 * A21, * B21, \
 51→                 * A31, * B31, \
 52→                 * A41, * B41, \
 53→                 * C1, * C2, * C3, * C4;
 54→    for (kk = 0; kk < col; kk += tiling_size)
 55→    {
 56→        kk_tiling_size = ((kk + tiling_size) > col ? col : (kk + tiling_size));
 57→        if ((kk + tiling_size) <= col)
 58→        {
 59→            max_kk_tiling_size = kk_tiling_size - (tiling_size & 3);
 60→        }
 61→        else
 62→        {
 63→            max_kk_tiling_size = col - ((col - kk) & 3);
 64→        }
 65→        for (cc = 0; cc < col2; cc += tiling_size)
 66→        {
 67→            cc_tiling_size = ((cc + tiling_size) > col2 ? col2 : (cc + tiling_size));
 68→            for (r = 0; r < max_row; r += 4)
 69→            {
 70→                int mulLen = cc_tiling_size - cc;
 71→                while (mulLen > 0)
 72→                {
 73→                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M4);
 74→                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
 75→                    NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0); //sum
 76→                    NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //sum
 77→                    NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0); //sum
 78→
 79→                    A11 = A + r * col + kk;
 80→                    A21 = A11 + col;
 81→                    A31 = A21 + col;
 82→                    A41 = A31 + col;
 83→                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
 84→                    B21 = B11 + col2;
 85→                    B31 = B21 + col2;
 86→                    B41 = B31 + col2;
 87→                    C1 = C + r * col2 + cc_tiling_size - mulLen;
 88→                    C2 = C1 + col2;
 89→                    C3 = C2 + col2;
 90→                    C4 = C3 + col2;
 91→                    for (k = kk; k < max_kk_tiling_size; k += 4)
 92→                    {
 93→                        DEF_VLOAD_V(NDS_VEC_V16, B11);
 94→                        DEF_VLOAD_V(NDS_VEC_V20, B21);
 95→                        DEF_VLOAD_V(NDS_VEC_V24, B31);
 96→                        DEF_VLOAD_V(NDS_VEC_V28, B41);
 97→                        MM_TYPE tmpa11 = *A11++;
 98→                        MM_TYPE tmpa21 = *A21++;
 99→                        MM_TYPE tmpa31 = *A31++;
100→                        MM_TYPE tmpa41 = *A41++;
101→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
102→                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa21, NDS_VEC_V16);
103→                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa31, NDS_VEC_V16);
104→                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa41, NDS_VEC_V16);
105→
106→                        MM_TYPE tmpa12 = *A11++;
107→                        MM_TYPE tmpa22 = *A21++;
108→                        MM_TYPE tmpa32 = *A31++;
109→                        MM_TYPE tmpa42 = *A41++;
110→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa12, NDS_VEC_V20);
111→                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa22, NDS_VEC_V20);
112→                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa32, NDS_VEC_V20);
113→                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa42, NDS_VEC_V20);
114→
115→                        MM_TYPE tmpa13 = *A11++;
116→                        MM_TYPE tmpa23 = *A21++;
117→                        MM_TYPE tmpa33 = *A31++;
118→                        MM_TYPE tmpa43 = *A41++;
119→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa13, NDS_VEC_V24);
120→                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa23, NDS_VEC_V24);
121→                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa33, NDS_VEC_V24);
122→                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa43, NDS_VEC_V24);
123→
124→                        MM_TYPE tmpa14 = *A11++;
125→                        MM_TYPE tmpa24 = *A21++;
126→                        MM_TYPE tmpa34 = *A31++;
127→                        MM_TYPE tmpa44 = *A41++;
128→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa14, NDS_VEC_V28);
129→                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa24, NDS_VEC_V28);
130→                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa34, NDS_VEC_V28);
131→                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa44, NDS_VEC_V28);
132→
133→                        B11 += 4 * col2;
134→                        B21 += 4 * col2;
135→                        B31 += 4 * col2;
136→                        B41 += 4 * col2;
137→                    }
138→                    for (; k < kk_tiling_size; k++)
139→                    {
140→                        DEF_VLOAD_V(NDS_VEC_V16, B11);
141→                        MM_TYPE tmpa11 = *A11++;
142→                        MM_TYPE tmpa21 = *A21++;
143→                        MM_TYPE tmpa31 = *A31++;
144→                        MM_TYPE tmpa41 = *A41++;
145→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
146→                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa21, NDS_VEC_V16);
147→                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa31, NDS_VEC_V16);
148→                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa41, NDS_VEC_V16);
149→
150→                        B11 += col2;
151→                    }
152→                    DEF_VLOAD_V(NDS_VEC_V16, C1);
153→                    DEF_VLOAD_V(NDS_VEC_V20, C2);
154→                    DEF_VLOAD_V(NDS_VEC_V24, C3);
155→                    DEF_VLOAD_V(NDS_VEC_V28, C4);
156→
157→                    NDS_VEC_VFADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16);
158→                    NDS_VEC_VFADD_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V20);
159→                    NDS_VEC_VFADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);
160→                    NDS_VEC_VFADD_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V28);
161→
162→                    DEF_VSTORE_V(NDS_VEC_V0, C1);
163→                    DEF_VSTORE_V(NDS_VEC_V4, C2);
164→                    DEF_VSTORE_V(NDS_VEC_V8, C3);
165→                    DEF_VSTORE_V(NDS_VEC_V12, C4);
166→                    mulLen -= vl;
167→                }
168→            }
169→            for (; r < row; r++)
170→            {
171→                int mulLen = cc_tiling_size - cc;
172→                while (mulLen > 0)
173→                {
174→                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M4);
175→                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
176→                    A11 = A + r * col + kk;
177→                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
178→                    B21 = B11 + col2;
179→                    B31 = B21 + col2;
180→                    B41 = B31 + col2;
181→                    C1 = C + r * col2 + cc_tiling_size - mulLen;
182→                    for (k = kk; k < max_kk_tiling_size; k += 4)
183→                    {
184→                        DEF_VLOAD_V(NDS_VEC_V16, B11);
185→                        DEF_VLOAD_V(NDS_VEC_V20, B21);
186→                        DEF_VLOAD_V(NDS_VEC_V24, B31);
187→                        DEF_VLOAD_V(NDS_VEC_V28, B41);
188→                        MM_TYPE tmpa11 = *A11++;
189→                        MM_TYPE tmpa12 = *A11++;
190→                        MM_TYPE tmpa13 = *A11++;
191→                        MM_TYPE tmpa14 = *A11++;
192→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
193→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa12, NDS_VEC_V20);
194→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa13, NDS_VEC_V24);
195→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa14, NDS_VEC_V28);
196→
197→                        B11 += 4 * col2;
198→                        B21 += 4 * col2;
199→                        B31 += 4 * col2;
200→                        B41 += 4 * col2;
201→                    }
202→                    for (; k < kk_tiling_size; k++)
203→                    {
204→                        DEF_VLOAD_V(NDS_VEC_V20, B11);
205→                        MM_TYPE tmpa11 = *A11++;
206→                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa11, NDS_VEC_V20);
207→                        B11 += col2;
208→                    }
209→                    DEF_VLOAD_V(NDS_VEC_V16, C1);
210→                    NDS_VEC_VFADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16);
211→                    DEF_VSTORE_V(NDS_VEC_V0, C1);
212→                    mulLen -= vl;
213→                }
214→            }
215→        }
216→    }
217→}
