219→static inline void vec_mat_mul_rvv_original(const MM_TYPE* src1, const MM_TYPE* src2, MM_TYPE* dst, uint32_t row, uint32_t col, uint32_t col2)
220→{
221→    long curRow, curCol, vl;
222→    long col_4 = col >> 2;
223→    long res_col = col & 3;
224→    long row_8 = row >> 3;
225→    long max_row = row_8 << 3;
226→
227→    for (curRow = 0; curRow < max_row; curRow += 8)
228→    {
229→        const MM_TYPE* C1 = dst + col2 * curRow;
230→        const MM_TYPE* C2 = C1 + col2;
231→        const MM_TYPE* C3 = C2 + col2;
232→        const MM_TYPE* C4 = C3 + col2;
233→        const MM_TYPE* C5 = C4 + col2;
234→        const MM_TYPE* C6 = C5 + col2;
235→        const MM_TYPE* C7 = C6 + col2;
236→        const MM_TYPE* C8 = C7 + col2;
237→
238→        long mulLen = col2;
239→        while (mulLen > 0)
240→        {
241→            NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
242→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //C
243→            NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0); //C
244→            NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0); //C
245→            NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0); //C
246→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //C
247→            NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0); //C
248→            NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0); //C
249→            NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0); //C
250→            const MM_TYPE* A1 = src1 + curRow * col;
251→            const MM_TYPE* A2 = A1 + col;
252→            const MM_TYPE* A3 = A2 + col;
253→            const MM_TYPE* A4 = A3 + col;
254→            const MM_TYPE* A5 = A4 + col;
255→            const MM_TYPE* A6 = A5 + col;
256→            const MM_TYPE* A7 = A6 + col;
257→            const MM_TYPE* A8 = A7 + col;
258→            const MM_TYPE* B0 = src2 + col2 - mulLen;
259→            const MM_TYPE* B1 = B0 + col2;
260→            const MM_TYPE* B2 = B1 + col2;
261→            const MM_TYPE* B3 = B2 + col2;
262→
263→            for (curCol = 0; curCol < col_4; curCol++)
264→            {
265→                DEF_VLOAD_V(NDS_VEC_V16, B0);
266→                DEF_VLOAD_V(NDS_VEC_V18, B1);
267→                DEF_VLOAD_V(NDS_VEC_V20, B2);
268→                DEF_VLOAD_V(NDS_VEC_V22, B3);
269→                MM_TYPE tmpa00 = *A1++;
270→                MM_TYPE tmpa10 = *A2++;
271→                MM_TYPE tmpa20 = *A3++;
272→                MM_TYPE tmpa30 = *A4++;
273→                NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa00, NDS_VEC_V16);
274→                NDS_VEC_VFMACC_VF(NDS_VEC_V2, tmpa10, NDS_VEC_V16);
275→                NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa20, NDS_VEC_V16);
276→                NDS_VEC_VFMACC_VF(NDS_VEC_V6, tmpa30, NDS_VEC_V16);
277→                MM_TYPE tmpa40 = *A5++;
278→                MM_TYPE tmpa50 = *A6++;
279→                MM_TYPE tmpa60 = *A7++;
280→                MM_TYPE tmpa70 = *A8++;
281→                NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa40, NDS_VEC_V16);
