284→                NDS_VEC_VFMACC_VF(NDS_VEC_V14, tmpa70, NDS_VEC_V16);
285→
286→                MM_TYPE tmpa01 = *A1++;
287→                MM_TYPE tmpa11 = *A2++;
288→                MM_TYPE tmpa21 = *A3++;
289→                MM_TYPE tmpa31 = *A4++;
290→                NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa01, NDS_VEC_V18);
